const root = $input.first().json;

const itemsRaw = root?.rss?.channel?.item || root?.channel?.item || [];
const items = Array.isArray(itemsRaw) ? itemsRaw : [itemsRaw];

function getText(v) {
  if (!v) return "";
  if (typeof v === "string") return v;
  if (typeof v === "object" && v._) return v._;
  if (typeof v === "object" && v["#text"]) return v["#text"]; 
  return String(v);
}

function stripHtml(html = "") {
  return String(html).replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim();
}

function parseDate(d) {
  const dt = new Date(d);
  if (isNaN(dt.getTime())) return "";
  return dt.toISOString().slice(0, 10);
}

function getImageFromHtml(html = "") {
  const m = String(html).match(/<img[^>]+src=["']([^"']+)["']/i);
  return m ? m[1] : "";
}

function makeId(link = "", title = "") {
  return (link || title || Date.now().toString())
    .replace(/[^a-zA-Z0-9]/g, "")
    .slice(-18);
}

const normalized = items.map((it) => {
  const title = getText(it.title);
  const link = getText(it.link);
  const body = getText(it["content:encoded"]) || getText(it.description) || "";
  const pubDate = getText(it.pubDate) || getText(it["dc:date"]) || "";

  return {
    id: makeId(link, title),
    title_en: title.trim(),
    summary_en: stripHtml(body).slice(0, 420),
    body_en: body,
    image: getImageFromHtml(body),
    source_url: link,
    date: parseDate(pubDate),
    category_en: "AI News",
    author_en: ""
  };
}).filter(x => x.title_en && x.source_url);

return normalized.map(x => ({ json: x }));

