const all = $input.all().map(x => x.json);

// Remove duplicates by URL
const map = new Map();
for (const n of all) {
  if (!n?.source_url) continue;
  if (!map.has(n.source_url)) map.set(n.source_url, n);
}

let list = Array.from(map.values());

// Sort newest
list.sort((a,b) => (b.date || "").localeCompare(a.date || ""));

// Pick top 60
list = list.slice(0, 60);

return [{
  json: {
    metadata: {
      sources: [
        "MIT Technology Review (AI)",
        "TechCrunch (AI)",
        "VentureBeat (AI)"
      ],
      total_articles: list.length,
      generated_at: new Date().toISOString(),
      translation_method: "LibreTranslate (self-hosted)",
      version: "1.0"
    },
    items: list
  }
}];

const title_ar = $items("Translate title_ar")[0].json.translatedText || "";
const summary_ar = $items("Translate summary_ar")[0].json.translatedText || "";

// Attach Arabic translations
return [{
  json: {
    ...$json,
    title_ar,
    summary_ar,
    category_ar: "أخبار الذكاء الاصطناعي",
    author_ar: "",
    body_ar: "" 
  }
}];

const items = $json.items || [];

return [{
  json: {
    metadata: {
      sources: [
        "MIT Technology Review (AI)",
